<script>
    document.addEventListener('DOMContentLoaded', function() {
        // Funkcija za inicijalizaciju slajdera
        function initializeSlider(containerSelector) {
            const sliderContainer = document.querySelector(containerSelector);
            if (!sliderContainer) return; // Provera da li kontejner postoji

            const slides = sliderContainer.querySelectorAll('.slide');
            if (slides.length === 0) return; // Provera da li ima slajdova

            const slideCount = slides.length;
            let currentSlide = 0;

            const existingBar = sliderContainer.querySelector('.progress_bar_hero');

            // Postavi slajder container kao relativni kontejner
            sliderContainer.style.position = 'relative';

            // Kreiraj wrapper za slajdove (klasa + isti layout kao pre inicijalizacije — bez FOUC-a)
            const slidesWrapper = document.createElement('div');
            slidesWrapper.className = 'hero-slider__track';
            slidesWrapper.style.cssText = `
            position: relative;
            width: 100%;
            height: 100%;
        `;

            // Premesti sve slajdove u wrapper
            slides.forEach((slide, index) => {
                slide.style.cssText = `
                position: absolute;
                top: 0;
                left: 0;
                width: 100%;
                height: 100%;
                opacity: ${index === 0 ? '1' : '0'};
                transition: opacity 0.5s ease-in-out;
            `;
                slidesWrapper.appendChild(slide);
            });

            // Ubaci wrapper na početak slajder kontejnera
            sliderContainer.insertBefore(slidesWrapper, sliderContainer.firstChild);

            // Progress bar: već u HTML-u (PHP) da nema treperenja; samo ubaci u track i koristi postojeći fill
            let progressIndicator;
            if (existingBar) {
                progressIndicator = existingBar.querySelector('.progress_bar_hero__fill');
                if (!progressIndicator) {
                    progressIndicator = document.createElement('div');
                    progressIndicator.className = 'progress_bar_hero__fill';
                    existingBar.appendChild(progressIndicator);
                }
                progressIndicator.style.width = `${100 / slideCount}%`;
                slidesWrapper.appendChild(existingBar);
            } else {
                const progressBarContainer = document.createElement('div');
                progressBarContainer.classList.add('progress_bar_hero');
                progressIndicator = document.createElement('div');
                progressIndicator.className = 'progress_bar_hero__fill';
                progressIndicator.style.width = `${100 / slideCount}%`;
                progressBarContainer.appendChild(progressIndicator);
                slidesWrapper.appendChild(progressBarContainer);
            }

            function updateProgress() {
                progressIndicator.style.width = `${((currentSlide + 1) * 100) / slideCount}%`;
            }

            function changeSlide() {
                slides[currentSlide].style.opacity = '0';
                currentSlide = (currentSlide + 1) % slideCount;
                slides[currentSlide].style.opacity = '1';
                updateProgress();
            }

            updateProgress();
            setInterval(changeSlide, 2000);
        }

        // Inicijalizuj oba slajdera
        initializeSlider('.desktop_slider_container');
        initializeSlider('.mobile_slider_container');
    });


    document.addEventListener('DOMContentLoaded', function() {
        const imgWrapper = document.querySelector('.primeri_jela_img_wrapper');
        const slides = imgWrapper.querySelectorAll('img');
        const slideCount = slides.length;
        const arrowLeft = document.querySelector('.arrow-left');
        const arrowRight = document.querySelector('.arrow-right');
        let currentSlide = 0;

        imgWrapper.style.position = 'relative';
        imgWrapper.style.overflow = 'hidden';

        const slideContainer = document.createElement('div');
        slideContainer.classList.add('slider-container');
        slideContainer.style.cssText = `
        position: relative;
        width: ${slideCount * 100}%;
        height: 100%;
        display: flex;
        transition: transform 0.5s ease-in-out;
    `;

        slides.forEach((slide) => {
            slide.style.cssText = `
            width: ${100 / slideCount}%;
            height: 100%;
        `;
            slideContainer.appendChild(slide);
        });

        imgWrapper.appendChild(slideContainer);

        const progressBarWrapper = document.querySelector('.progress_bar');
        const progressIndicator = document.createElement('div');
        progressIndicator.style.cssText = `
        width: ${(1 / slideCount) * 100}%;
        height: 100%;
        background: #0E0E0E;
        transition: width 0.5s ease-in-out;
    `;
        progressBarWrapper.appendChild(progressIndicator);

        function updateProgress() {
            progressIndicator.style.width = `${((currentSlide + 1) * 100) / slideCount}%`;
        }

        function changeSlide(direction) {
            if (direction === 'next') {
                currentSlide = (currentSlide + 1) % slideCount;
            } else {
                currentSlide = (currentSlide - 1 + slideCount) % slideCount;
            }

            slideContainer.style.transform = `translateX(-${(100 / slideCount) * currentSlide}%)`;
            updateProgress();
        }

        arrowLeft.addEventListener('click', () => {
            changeSlide('prev');
            resetAutoSlide();
        });
        arrowRight.addEventListener('click', () => {
            changeSlide('next');
            resetAutoSlide();
        });

        updateProgress();


        let autoSlideInterval;
        const mediaQuery = window.matchMedia('(max-width: 600px)');

        function startAutoSlide() {
            if (!autoSlideInterval) {
                autoSlideInterval = setInterval(() => changeSlide('next'), 4000);
            }
        }

        function stopAutoSlide() {
            if (autoSlideInterval) {
                clearInterval(autoSlideInterval);
                autoSlideInterval = null;
            }
        }

        function resetAutoSlide() {
            stopAutoSlide();
            if (mediaQuery.matches) {
                startAutoSlide();
            }
        }

        function handleViewportChange() {
            if (mediaQuery.matches) {
                startAutoSlide();
            } else {
                stopAutoSlide();
            }
        }

        mediaQuery.addEventListener('change', handleViewportChange);
        handleViewportChange();

        // Swipe functionality
        let startX = 0;
        let endX = 0;

        slideContainer.addEventListener('touchstart', (event) => {
            startX = event.touches[0].clientX;
        });

        slideContainer.addEventListener('touchmove', (event) => {
            endX = event.touches[0].clientX;
        });

        slideContainer.addEventListener('touchend', () => {
            const swipeDistance = endX - startX;

            if (Math.abs(swipeDistance) > 50) { // Minimum swipe distance
                if (swipeDistance > 0) {
                    changeSlide('prev'); // Swipe right
                } else {
                    changeSlide('next'); // Swipe left
                }
                resetAutoSlide(); // Reset interval after swipe
            }
            startX = 0; // Reset
            endX = 0; // Reset
        });

        // Cleanup
        window.addEventListener('beforeunload', stopAutoSlide);
    });


    document.addEventListener('DOMContentLoaded', function() {
        const faqCards = document.querySelectorAll('.faq_card');

        faqCards.forEach(card => {
            card.addEventListener('click', function(e) {
                const currentParagraph = this.querySelector('.faq_paragraph');

                // Zatvori sve otvorene kartice
                faqCards.forEach(otherCard => {
                    if (otherCard !== this && otherCard.classList.contains('active')) {
                        otherCard.classList.remove('active');
                        const otherParagraph = otherCard.querySelector('.faq_paragraph');
                        otherParagraph.style.height = '0px';
                    }
                });

                // Toggle trenutne kartice
                if (!this.classList.contains('active')) {
                    this.classList.add('active');
                    currentParagraph.style.height = currentParagraph.scrollHeight + 'px';
                } else {
                    this.classList.remove('active');
                    currentParagraph.style.height = '0px';
                }
            });
        });
    });

    document.addEventListener('DOMContentLoaded', function() {
        function initializeAccordion() {
            const packages = document.querySelectorAll('.paket');

            packages.forEach((package) => {
                const currentParagraph = package.querySelector('.text');
                if (window.innerWidth < 600) {
                    // Apply accordion behavior
                    package.addEventListener('click', function() {
                        // Close all other open cards
                        packages.forEach((otherPackage) => {
                            if (otherPackage !== this && otherPackage.classList.contains('active')) {
                                otherPackage.classList.remove('active');
                                const otherParagraph = otherPackage.querySelector('.text');
                                otherParagraph.style.height = '0px';
                            }
                        });

                        // Toggle the current card
                        if (!this.classList.contains('active')) {
                            this.classList.add('active');
                            currentParagraph.style.height = currentParagraph.scrollHeight + 'px';
                        } else {
                            this.classList.remove('active');
                            currentParagraph.style.height = '0px';
                        }
                    });
                } else {
                    // Reset styles for desktop
                    package.classList.remove('active');
                    if (currentParagraph) {
                        currentParagraph.style.height = '';
                    }
                    // Remove event listeners to prevent duplicates
                    package.replaceWith(package.cloneNode(true));
                }
            });
        }

        // Initialize accordion on load
        initializeAccordion();

        // Reinitialize on resize
        window.addEventListener('resize', initializeAccordion);
    });


    jQuery(document).ready(function($) {
        const $slider = $('.slider-wrapper-insta-feed');

        function calculateSlidesToShow() {
            // Example: Each slide has a fixed width of 200px + margin
            const containerWidth = $slider.width();
            let slideWidth;

            if (window.innerWidth > 600) {
                slideWidth = 560;
            } else {
                slideWidth = 213;
            }

            return Math.max(1, containerWidth / slideWidth); // Ensure at least 1 slide
        }

        function initializeSlider() {
            $slider.slick({
                slidesToShow: calculateSlidesToShow(),
                slidesToScroll: 1,
                arrows: false,
                dots: false,
                infinite: false,
                responsive: [{
                    breakpoint: 1024,
                    settings: {
                        slidesToShow: 1.41,
                    }
                }, ]
            });
        }

        function updateSlidesToShow() {
            const newSlidesToShow = calculateSlidesToShow();
            $slider.slick('slickSetOption', 'slidesToShow', newSlidesToShow, true);
        }

        // Initialize the slider
        initializeSlider();

        // Update slidesToShow on window resize (use .on() — .resize() shorthand is deprecated in jQuery Migrate 3.x)
        $(window).on('resize', updateSlidesToShow);

        // Custom arrows (use .on('click') — .click(fn) shorthand is deprecated in jQuery Migrate 3.x)
        $('.prev-arrow').on('click', function() {
            $slider.slick('slickPrev');
        });

        $('.next-arrow').on('click', function() {
            $slider.slick('slickNext');
        });
    });
</script>
